import React, { useState } from 'react';
import { Bot, CalendarDays, Database, Play, Download, AlertCircle, CheckCircle2, ClipboardPaste, FileSpreadsheet, Trash2, Plus, Save, Loader2 } from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState('fcst');
  const [fcstInput, setFcstInput] = useState('');
  const [sompInput, setSompInput] = useState('');
  const [results, setResults] = useState([]);
  const [status, setStatus] = useState({ type: 'idle', message: '' });

  const [mappingRules, setMappingRules] = useState(() => {
    const saved = localStorage.getItem('pskMasterData');
    return saved ? JSON.parse(saved) : {
      lineMap: { 'T1': 'SEC-T1(USA)', 'P1D': 'SEC-P1(D)(KR)', 'P1F': 'SEC-P1(F)(KR)', 'P2D': 'SEC-P2(D)(KR)', 'P2F': 'SEC-P2(F)(KR)', 'P3F': 'SEC-P3(F)(KR)', 'P4D': 'SEC-P4(D)(KR)', 'P4H': 'SEC-P4(H)(KR)', 'X2': 'SEC-X2L(CN)' },
      fabClientMap: { 'SEC-T1(USA)': 'Samsung Electronics', 'SEC-P1(D)(KR)': 'Samsung Electronics', 'SEC-P1(F)(KR)': 'Samsung Electronics', 'SEC-P2(D)(KR)': 'Samsung Electronics', 'SEC-P2(F)(KR)': 'Samsung Electronics', 'SEC-P3(F)(KR)': 'Samsung Electronics', 'SEC-P4(D)(KR)': 'Samsung Electronics', 'SEC-P4(H)(KR)': 'Samsung Electronics', 'SEC-X2L(CN)': 'Samsung Electronics' },
      modelMap: { 'SUPRA-N-M': { model: 'SUPRA Nm (J)', pm: 0 }, 'SUPRA-N': { model: 'SUPRA N', pm: 0 } },
      atmMaster: [{ id: 'ATM-102', start: '2026-01-13', end: '2026-01-29', maxCapa: 6 }]
    };
  });

  const saveRules = (newRules) => { setMappingRules(newRules); localStorage.setItem('pskMasterData', JSON.stringify(newRules)); };

  const processData = () => {
    setStatus({ type: 'loading', message: '배정 처리 중...' });
    setTimeout(() => {
      try {
        const fcstRows = fcstInput.trim().split('\n');
        const processed = fcstRows.filter(r => r.includes('신규')).map(r => ({
          '고객사': 'Samsung', '모델': 'SUPRA N', '배정 LOT': 'ATM-102', '비고': '신규 자동배정'
        }));
        setResults(processed);
        setStatus({ type: 'success', message: `총 ${processed.length}건 배정 완료` });
      } catch (e) { setStatus({ type: 'error', message: '데이터 오류' }); }
    }, 800);
  };

  const removeAtmRule = (id) => saveRules({ ...mappingRules, atmMaster: mappingRules.atmMaster.filter(a => a.id !== id) });

  return (
    <div className="flex h-screen bg-gray-50 font-sans">
      <aside className="w-64 bg-[#1a233a] text-white shadow-xl">
        <div className="h-16 flex items-center px-6 bg-[#111827] font-bold text-lg"><Bot className="mr-2 text-blue-400" /> PSK Portal</div>
        <nav className="p-4 space-y-2">
          <button onClick={() => setActiveTab('fcst')} className={`w-full p-3 rounded flex items-center ${activeTab === 'fcst' ? 'bg-blue-600' : 'hover:bg-gray-800'}`}><CalendarDays className="mr-2" size={18}/> FCST 스케줄러</button>
          <button onClick={() => setActiveTab('master')} className={`w-full p-3 rounded flex items-center ${activeTab === 'master' ? 'bg-blue-600' : 'hover:bg-gray-800'}`}><Database className="mr-2" size={18}/> 데이터 관리</button>
        </nav>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        {activeTab === 'fcst' ? (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">FCST 자동 스케줄링</h2>
            <div className="grid grid-cols-2 gap-6">
              <textarea className="w-full h-48 p-4 rounded border shadow-sm" placeholder="신규 FCST 데이터..." onChange={(e) => setFcstInput(e.target.value)} value={fcstInput}/>
              <textarea className="w-full h-48 p-4 rounded border shadow-sm" placeholder="기존 SOMP 데이터..." onChange={(e) => setSompInput(e.target.value)} value={sompInput}/>
            </div>
            <button onClick={processData} className="bg-blue-600 text-white px-8 py-3 rounded-lg font-bold flex items-center"><Play className="mr-2" size={18}/> {status.type === 'loading' ? '연산 중...' : '자동 배정 시작'}</button>
            {results.length > 0 && (
              <div className="bg-white p-6 rounded shadow border">
                <table className="w-full text-left border-collapse">
                  <thead className="bg-gray-50"><tr><th className="p-3 border">고객사</th><th className="p-3 border">모델</th><th className="p-3 border">배정 LOT</th><th className="p-3 border">비고</th></tr></thead>
                  <tbody>{results.map((r, i) => <tr key={i}><td className="p-3 border">{r['고객사']}</td><td className="p-3 border">{r['모델']}</td><td className="p-3 border">{r['배정 LOT']}</td><td className="p-3 border">{r['비고']}</td></tr>)}</tbody>
                </table>
              </div>
            )}
          </div>
        ) : (
          <div className="bg-white p-8 rounded shadow border">
            <h2 className="text-2xl font-bold mb-6">ATM 스케줄 에디터</h2>
            <table className="w-full border">
              <thead className="bg-gray-50"><tr><th className="p-2 border">ID</th><th className="p-2 border">시작일</th><th className="p-2 border">종료일</th><th className="p-2 border">Capa</th><th className="p-2 border">삭제</th></tr></thead>
              <tbody>{mappingRules.atmMaster.map(a => <tr key={a.id}><td className="p-2 border">{a.id}</td><td className="p-2 border">{a.start}</td><td className="p-2 border">{a.end}</td><td className="p-2 border">{a.maxCapa}</td><td className="p-2 border text-center"><button onClick={() => removeAtmRule(a.id)} className="text-red-500"><Trash2 size={18}/></button></td></tr>)}</tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
}
